14	TEST_CASE("magic and version are stable wire constants")
15	{
16	  // 'AHYB' read little-endian: 'A'=0x41 'H'=0x48 'Y'=0x59 'B'=0x42
17	  CHECK(HYBRID_STATE_MAGIC == 0x42594841u);
18	  CHECK(HYBRID_STATE_VERSION == 1u);
19	}
