21	TEST_CASE("struct is standard-layout, trivially copyable, packed")
22	{
23	  CHECK(std::is_standard_layout_v<hybrid_state_v1>);
24	  CHECK(std::is_trivially_copyable_v<hybrid_state_v1>);
25	  // packed: fields are 8-byte aligned naturally, so packing should not shrink
26	  // sizeof. We assert no implicit tail padding either.
27	  CHECK(sizeof(hybrid_state_v1) % 8 == 0);
28	}
