31	{
32	  CHECK(offsetof(hybrid_state_v1, magic) == 0);
33	  CHECK(offsetof(hybrid_state_v1, version) == 4);
34	  CHECK(offsetof(hybrid_state_v1, flags) == 8);
35	  CHECK(offsetof(hybrid_state_v1, hart_id) == 12);
36	  CHECK(offsetof(hybrid_state_v1, pc) == 16);
37	  CHECK(offsetof(hybrid_state_v1, priv) == 24);
38	}
