40	TEST_CASE("GPR and FPR are 32 * uint64_t each, contiguous")
41	{
42	  CHECK(offsetof(hybrid_state_v1, gpr) == 32);
43	  CHECK(sizeof(((hybrid_state_v1*) 0)->gpr) == 32 * sizeof(uint64_t));
44	  CHECK(offsetof(hybrid_state_v1, fpr) == 32 + 32 * 8);
45	  CHECK(sizeof(((hybrid_state_v1*) 0)->fpr) == 32 * sizeof(uint64_t));
46	}
