51	  CHECK((HYBRID_VLEN_BYTES_MAX & (HYBRID_VLEN_BYTES_MAX - 1)) == 0);  // power of 2
52	  CHECK(sizeof(((hybrid_state_v1*) 0)->vreg) == 32u * HYBRID_VLEN_BYTES_MAX);
