58	  CHECK(sizeof(((hybrid_state_v1*) 0)->pmpaddr) == HYBRID_PMP_ADDR_NUM * sizeof(uint64_t));
59	  CHECK(HYBRID_PMP_ADDR_NUM == 64);
60	  CHECK(HYBRID_PMP_CFG_NUM == 16);
61	}
