68	TEST_CASE("byte-level roundtrip via memcpy preserves all fields")
69	{
70	  hybrid_state_v1 src{};
71	  src.magic = HYBRID_STATE_MAGIC;
72	  src.version = HYBRID_STATE_VERSION;
73	  src.flags = HYBRID_FLAG_RV64 | HYBRID_FLAG_FP | HYBRID_FLAG_V;
74	  src.hart_id = 1;
75	  src.pc = 0x80001234ULL;
76	  src.priv = 3;  // M-mode
77	
78	  for (int i = 0; i < 32; ++i) {
79	    src.gpr[i] = 0xCAFE0000ULL + i;
80	    src.fpr[i] = 0xF00D0000ULL + i;
81	  }
82	  src.mstatus = 0xa00040080ULL;
83	  src.mepc    = 0x80002000ULL;
84	  src.mtvec   = 0x80000000ULL;
85	  src.satp    = 0x8000000000080000ULL;
86	  src.vstart  = 0;
87	  src.vtype   = 0xc0;
88	  src.vl      = 4;
89	  src.vlenb   = 16;
90	  for (size_t i = 0; i < sizeof(src.vreg); ++i) src.vreg[i] = (uint8_t) i;
91	
92	  alignas(hybrid_state_v1) unsigned char buf[sizeof(hybrid_state_v1)];
93	  std::memcpy(buf, &src, sizeof(src));
94	  hybrid_state_v1 dst{};
95	  std::memcpy(&dst, buf, sizeof(dst));
96	
97	  CHECK(dst.magic == HYBRID_STATE_MAGIC);
98	  CHECK(dst.version == HYBRID_STATE_VERSION);
99	  CHECK(dst.flags == src.flags);
100	  CHECK(dst.hart_id == 1);
101	  CHECK(dst.pc == 0x80001234ULL);
102	  CHECK(dst.priv == 3);
103	  for (int i = 0; i < 32; ++i) {
104	    CHECK(dst.gpr[i] == 0xCAFE0000ULL + i);
105	    CHECK(dst.fpr[i] == 0xF00D0000ULL + i);
106	  }
107	  CHECK(dst.mstatus == 0xa00040080ULL);
108	  CHECK(dst.mepc == 0x80002000ULL);
109	  CHECK(dst.mtvec == 0x80000000ULL);
110	  CHECK(dst.satp == 0x8000000000080000ULL);
111	  CHECK(dst.vtype == 0xc0);
112	  CHECK(dst.vl == 4);
113	  CHECK(dst.vlenb == 16);
114	  CHECK(std::memcmp(dst.vreg, src.vreg, sizeof(src.vreg)) == 0);
115	}
